{"code":"// Find PRs whose body mentions "Closes ENG-" or similar Linear issue references
const prsClosingLinear = prDetails.filter(p => {
  const body = p.body || '';
  return /closes\s+eng-\d+/i.test(body);
});
prsClosingLinear.map(p => ({number: p.number, repo: p.repo, title: p.title, linearRef: (p.body || '').match(/closes\s+(eng-\d+)/i)?.[1]}))"}

{"code":"const results = [];
for (const pr of prsClosingLinear) {
  const title = `Verify: ${pr.title}`;
  const created = github__create_issue({repo: "acme/web", title, body: `Created from merged PR #${pr.number} in ${pr.repo} which closed a Linear issue.`});
  results.push({prNumber: pr.number, repo: pr.repo, issueTitle: title, issueNumber: created.number});
}
results"}
